import React from 'react';
import { View } from 'react-native';
import type {
  SDUIScreen,
  SDUIComponent,
  SDUIComponentRegistry,
  SDUIContext,
} from '../models';
import { interpolateDeep } from '../utils/interpolation';
import { getDefaultRegistry, getRenderer } from '../registry';
import FallbackComponent from './FallbackComponent';

interface ScreenRendererProps {
  screen: SDUIScreen;
  registry?: SDUIComponentRegistry;
}

function renderComponent(
  component: SDUIComponent,
  context: SDUIContext,
  registry: SDUIComponentRegistry,
  key: string,
) {
  const interpolatedProps = interpolateDeep(component.props, context);

  const Renderer = getRenderer(registry, component.type);

  if (!Renderer) {
    return (
      <FallbackComponent
        key={key}
        type={component.type}
        props={interpolatedProps}
      />
    );
  }

  return <Renderer key={key} props={interpolatedProps} context={context} />;
}

export default function ScreenRenderer({
  screen,
  registry,
}: ScreenRendererProps) {
  const activeRegistry = registry ?? getDefaultRegistry();
  const { context, header, body, footer } = screen;

  return (
    <View style={{ flex: 1 }}>
      {header && renderComponent(header, context, activeRegistry, 'header')}

      <View style={{ flex: 1 }}>
        {(body ?? []).map((component, index) =>
          renderComponent(
            component,
            context,
            activeRegistry,
            `${component.type}-${index}`,
          ),
        )}
      </View>

      {footer && renderComponent(footer, context, activeRegistry, 'footer')}
    </View>
  );
}

