import React from 'react';
import { Button } from '@semparar/design-system-app';
import type {
  SDUIComponentProps,
  SDUIContext,
  SDUIConditional,
} from '../models';
import { evaluateRule } from '../utils/jsonLogic';

interface ButtonProps extends SDUIComponentProps {
  text: string;
  disabled?: boolean;
  enabled?: SDUIConditional;
  mt?: string;
  mb?: string;
  icon?: string;
  isLoading?: boolean;
  testID?: string;
}

export default function ButtonAdapter({
  props,
  context,
}: {
  props: ButtonProps;
  context: SDUIContext;
}) {
  const { text, disabled, enabled, mt, mb, icon, isLoading, testID } = props;

  const isEnabled = enabled ? evaluateRule(enabled.rule, context) : true;
  const isDisabled = !!disabled || !isEnabled;

  return (
    <Button
      text={String(text)}
      onPress={() => {}}
      disabled={isDisabled}
      mt={mt}
      mb={mb}
      icon={icon}
      isLoading={!!isLoading}
      testID={testID}
    />
  );
}

