import React, { useState } from 'react';
import { View, ScrollView } from 'react-native';
import { Text, Box, Button, SeparatorHorizontal } from '@semparar/design-system-app';
import type { Meta, StoryObj } from 'storybook/internal/types';
import type { SDUIScreen } from '../services/sdui/models';
import ScreenRenderer from '../services/sdui/renderer/ScreenRenderer';
import { registerAllAdapters } from '../services/sdui/adapters';

registerAllAdapters();

function buildScreen(pointsValue: number, showRules: boolean): SDUIScreen {
  return {
    id: 'conditionals_demo',
    context: {
      form: { points: pointsValue },
      balance: { available: 1000 },
      flags: { showRules },
    },
    body: [
      {
        type: 'heading',
        props: { text: 'Conditional Visibility Demo' },
      },
      {
        type: 'text',
        props: {
          text: `Points entered: ${pointsValue} | Balance: 1,000 | Show rules: ${showRules}`,
        },
      },
      {
        type: 'separator',
        props: {},
      },
      {
        type: 'balance_display',
        props: {
          label: 'Pontos disponíveis:',
          pointsFormatted: '1.000',
          priceFormatted: 'R$ 10,00',
        },
      },
      {
        type: 'text',
        props: { text: 'This alert only shows when points > 0:' },
      },
      {
        type: 'alert',
        props: {
          label: `Você selecionou ${pointsValue} pontos`,
          type: 'highlight',
        },
        visible: {
          rule: { '>': [{ var: 'form.points' }, 0] },
        },
      },
      {
        type: 'text',
