cat << 'SCRIPT' > .storybook/screenshots/capture-conditionals.mjs
import { chromium } from 'playwright';
import { fileURLToPath } from 'url';
import { dirname, join } from 'path';

const __filename = fileURLToPath(import.meta.url);
const __dirname = dirname(__filename);

const browser = await chromium.launch({ headless: true });
const page = await browser.newPage({ viewport: { width: 1400, height: 900 } });

await page.goto('http://localhost:6006/?path=/story/sdui-conditionals--demo');
await page.waitForTimeout(3000);

const frame = page.frameLocator('#storybook-preview-iframe');

// Screenshot 1: 0 points (initial state - button disabled, no selection alert)
await page.screenshot({ path: join(__dirname, 'sdui-conditionals-0pts.png'), fullPage: false });
console.log('Screenshot 1: 0 points');

// Click 500 pts
await frame.locator('text=500 pts').click();
await page.waitForTimeout(1000);
await page.screenshot({ path: join(__dirname, 'sdui-conditionals-500pts.png'), fullPage: false });
console.log('Screenshot 2: 500 points');

// Click 1500 pts (exceeds balance)
await frame.locator('text=1500 pts').click();
await page.waitForTimeout(1000);
await page.screenshot({ path: join(__dirname, 'sdui-conditionals-1500pts.png'), fullPage: false });
console.log('Screenshot 3: 1500 points');

// Toggle rules off
await frame.locator('text=Hide rules').click();
await page.waitForTimeout(1000);
await page.screenshot({ path: join(__dirname, 'sdui-conditionals-norules.png'), fullPage: false });
console.log('Screenshot 4: Rules hidden');

await browser.close();
console.log('Done.');
