        <Comp
          props={{
            text: 'Submit',
            enabled: { rule: { '>': [{ var: 'form.points' }, 0] } },
          }}
          context={context}
        />,
      );
      expect(getByText('Submit')).toBeTruthy();
    });

    it('enables button when enabled rule evaluates to true', () => {
      const Comp = adapters.button;
      const context: SDUIContext = { form: { points: 500 } };
      const { getByText } = render(
        <Comp
          props={{
            text: 'Submit',
            enabled: { rule: { '>': [{ var: 'form.points' }, 0] } },
          }}
          context={context}
        />,
      );
      expect(getByText('Submit')).toBeTruthy();
    });

    it('respects disabled prop even when enabled rule is true', () => {
      const Comp = adapters.button;
      const context: SDUIContext = { form: { points: 500 } };
      const { getByText } = render(
        <Comp
          props={{
            text: 'Submit',
            disabled: true,
            enabled: { rule: { '>': [{ var: 'form.points' }, 0] } },
          }}
          context={context}
        />,
      );
      expect(getByText('Submit')).toBeTruthy();
    });
  });

  describe('LinkAdapter', () => {
    it('renders link text', () => {
      const Comp = adapters.link;
      const { getByText } = render(
        <Comp props={{ text: 'Exibir regras' }} context={emptyContext} />,
      );
      expect(getByText('Exibir regras')).toBeTruthy();
    });
  });

  describe('AlertAdapter', () => {
    it('renders alert label', () => {
      const Comp = adapters.alert;
      const { getByText } = render(
        <Comp
          props={{ label: 'Info message', type: 'highlight' }}
          context={emptyContext}
        />,
      );
      expect(getByText('Info message')).toBeTruthy();
    });
  });

  describe('ListTextIconAdapter', () => {
    it('renders list items', () => {
      const Comp = adapters.list_text_icon;
      const items = [
        { icon: 'icon-check', description: 'Item 1' },
        { icon: 'icon-calendar', description: 'Item 2' },
      ];
      const { getByText } = render(
        <Comp props={{ items }} context={emptyContext} />,
      );
      expect(getByText('Item 1')).toBeTruthy();
      expect(getByText('Item 2')).toBeTruthy();
    });
  });

  describe('SeparatorAdapter', () => {
    it('renders separator', () => {
      const Comp = adapters.separator;
      const { getByTestId } = render(
        <Comp props={{}} context={emptyContext} />,
      );
      expect(getByTestId('separator')).toBeTruthy();
    });
  });

  describe('IconTextRowAdapter', () => {
    it('renders icon and text', () => {
      const Comp = adapters.icon_text_row;
      const { getByText } = render(
        <Comp
          props={{ icon: 'icon-check', text: 'Rule description' }}
          context={emptyContext}
        />,
      );
      expect(getByText('icon-check')).toBeTruthy();
      expect(getByText('Rule description')).toBeTruthy();
    });
  });

  describe('SectionHeadingAdapter', () => {
    it('renders section heading', () => {
      const Comp = adapters.section_heading;
      const { getByText } = render(
        <Comp props={{ text: 'Regras de uso' }} context={emptyContext} />,
      );
      expect(getByText('Regras de uso')).toBeTruthy();
    });
  });
});

